#include <stdio.h>
#include <errno.h>
#include <string.h>

int main() {
  FILE* file = fopen("nonexistent.txt", "r");
  if (file == NULL) {
    printf("errno dəyəri: %d\n", errno);
    perror("Fayl açılmadı");
    printf("Səhv mesajı: %s\n", strerror(errno));
  } else {
    printf("Fayl uğurla açıldı\n");
    fclose(file);
  }
  return 0;
}
// Output (Pyodide-da fayl sistemi olmadığından ümumi nümunədir):
// errno dəyəri: 2
// Fayl açılmadı: No such file or directory
// Səhv mesajı: No such file or directory

#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <string.h>

int main() {
  int* ptr = (int*)malloc(1000000000 * sizeof(int)); // Böyük yaddaş tələbi
  if (ptr == NULL) {
    printf("errno dəyəri: %d\n", errno);
    perror("Yaddaş ayrılmadı");
    printf("Səhv mesajı: %s\n", strerror(errno));
  } else {
    printf("Yaddaş uğurla ayrıldı\n");
    free(ptr);
  }
  return 0;
}
// Output (yaddaş çatışmazlığı olduqda):
// errno dəyəri: 12
// Yaddaş ayrılmadı: Cannot allocate memory
// Səhv mesajı: Cannot allocate memory

