    printf("errno value: %d\n", errno);
    perror("Failed to open file");
    printf("Error message: %s\n", strerror(errno));
  } else {
    printf("File opened successfully\n");
    fclose(file);
  }
  return 0;
}
// Output (generic example, as Pyodide lacks file system):
// errno value: 2
// Failed to open file: No such file or directory
// Error message: No such file or directory

#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <string.h>

int main() {
  int* ptr = (int*)malloc(1000000000 * sizeof(int)); // Large memory request
  if (ptr == NULL) {
    printf("errno value: %d\n", errno);
    perror("Memory allocation failed");
    printf("Error message: %s\n", strerror(errno));
  } else {
    printf("Memory allocated successfully\n");
    free(ptr);
  }
  return 0;
}
// Output (if memory allocation fails):
// errno value: 12
// Memory allocation failed: Cannot allocate memory
// Error message: Cannot allocate memory

